 44 bool KnownFPClass::isKnownNeverLogicalPosZero(DenormalMode Mode) const {
 45   if (!isKnownNeverPosZero())
 46     return false;
 47 
 48   // If we know there are no denormals, nothing can be flushed to zero.
 49   if (isKnownNeverSubnormal())
 50     return true;
 51 
 52   switch (Mode.Input) {
 53   case DenormalMode::IEEE:
 54     return true;
 55   case DenormalMode::PreserveSign:
 56     // Negative subnormal won't flush to +0
 57     return isKnownNeverPosSubnormal();
 58   case DenormalMode::PositiveZero:
 59   default:
 60     // Both positive and negative subnormal could flush to +0
 61     return false;
 62   }
 63 
 64   llvm_unreachable("covered switch over denormal mode");
 65 }
 66 
 67 void KnownFPClass::propagateDenormal(const KnownFPClass &Src,
 68                                      DenormalMode Mode) {
 69   KnownFPClasses = Src.KnownFPClasses;
 70   // If we aren't assuming the source can't be a zero, we don't have to check if
 71   // a denormal input could be flushed.
 72   if (!Src.isKnownNeverPosZero() && !Src.isKnownNeverNegZero())
 73     return;
 74 
 75   // If we know the input can't be a denormal, it can't be flushed to 0.
 76   if (Src.isKnownNeverSubnormal())
 77     return;
 78 
 79   if (!Src.isKnownNeverPosSubnormal() && Mode != DenormalMode::getIEEE())
 80     KnownFPClasses |= fcPosZero;
 81 
 82   if (!Src.isKnownNeverNegSubnormal() && Mode != DenormalMode::getIEEE()) {
 83     if (Mode != DenormalMode::getPositiveZero())
 84       KnownFPClasses |= fcNegZero;
 85 
 86     if (Mode.Input == DenormalMode::PositiveZero ||
 87         Mode.Output == DenormalMode::PositiveZero ||
 88         Mode.Input == DenormalMode::Dynamic ||
 89         Mode.Output == DenormalMode::Dynamic)
 90       KnownFPClasses |= fcPosZero;
 91   }
 92 }
 93 
 94 KnownFPClass KnownFPClass::canonicalize(const KnownFPClass &KnownSrc,
 95                                         DenormalMode DenormMode) {
 96   KnownFPClass Known;
 97 
 98   // This is essentially a stronger form of
 99   // propagateCanonicalizingSrc. Other "canonicalizing" operations don't
100   // actually have an IR canonicalization guarantee.
101 
102   // Canonicalize may flush denormals to zero, so we have to consider the
103   // denormal mode to preserve known-not-0 knowledge.
104   Known.KnownFPClasses = KnownSrc.KnownFPClasses | fcZero | fcQNan;
105 
106   // Stronger version of propagateNaN
107   // Canonicalize is guaranteed to quiet signaling nans.
108   if (KnownSrc.isKnownNeverNaN())
109     Known.knownNot(fcNan);
110   else
111     Known.knownNot(fcSNan);
112 
113   // FIXME: Missing check of IEEE like types.
114 
115   // If the parent function flushes denormals, the canonical output cannot be a
116   // denormal.
117   if (DenormMode == DenormalMode::getIEEE()) {
118     if (KnownSrc.isKnownNever(fcPosZero))
119       Known.knownNot(fcPosZero);
120     if (KnownSrc.isKnownNever(fcNegZero))
121       Known.knownNot(fcNegZero);
122     return Known;
123   }
124 
125   if (DenormMode.inputsAreZero() || DenormMode.outputsAreZero())
126     Known.knownNot(fcSubnormal);
127 
128   if (DenormMode == DenormalMode::getPreserveSign()) {
129     if (KnownSrc.isKnownNever(fcPosZero | fcPosSubnormal))
130       Known.knownNot(fcPosZero);
131     if (KnownSrc.isKnownNever(fcNegZero | fcNegSubnormal))
132       Known.knownNot(fcNegZero);
133     return Known;
134   }
135 
136   if (DenormMode.Input == DenormalMode::PositiveZero ||
137       (DenormMode.Output == DenormalMode::PositiveZero &&
138        DenormMode.Input == DenormalMode::IEEE))
139     Known.knownNot(fcNegZero);
140 
141   return Known;
142 }
143 
144 KnownFPClass KnownFPClass::exp(const KnownFPClass &KnownSrc) {
145   KnownFPClass Known;
146   Known.knownNot(fcNegative);
147 
148   Known.propagateNaN(KnownSrc);
149 
150   if (KnownSrc.cannotBeOrderedLessThanZero()) {
151     // If the source is positive this cannot underflow.
152     Known.knownNot(fcPosZero);
153 
154     // Cannot introduce denormal values.
155     Known.knownNot(fcPosSubnormal);
156   }
157 
158   // If the source is negative, this cannot overflow to infinity.
159   if (KnownSrc.cannotBeOrderedGreaterThanZero())
160     Known.knownNot(fcPosInf);
161 
162   return Known;
163 }
164 
165 void KnownFPClass::propagateCanonicalizingSrc(const KnownFPClass &Src,
166                                               DenormalMode Mode) {
167   propagateDenormal(Src, Mode);
168   propagateNaN(Src, /*PreserveSign=*/true);
